// src/pages/AdminDashboard.jsx
import React, { useEffect, useState } from "react";
import {
  Box,
  Typography,
  Grid,
  Card,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Paper,
  Button,
  CircularProgress,
  Alert,
  Tabs,
  Tab,
  Modal,
} from "@mui/material";
import axios from "axios";
import { useNavigate } from "react-router-dom";

const API = process.env.REACT_APP_API_URL || "http://localhost:5000";

export default function AdminDashboard() {
  const [users, setUsers] = useState([]);
  const [riders, setRiders] = useState([]);
  const [captains, setCaptains] = useState([]);
  const [pendingCaptains, setPendingCaptains] = useState([]);
  const [rides, setRides] = useState([]);
  const [overview, setOverview] = useState({});
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [tab, setTab] = useState("overview");

  const [modalOpen, setModalOpen] = useState(false);
  const [selectedUser, setSelectedUser] = useState(null);

  const navigate = useNavigate();
  const token = localStorage.getItem("token");

  const fetchData = async () => {
    setLoading(true);
    setError("");
    try {
      const headers = { Authorization: `Bearer ${token}` };
      const [overviewRes, usersRes, ridersRes, captainsRes, pendingRes, ridesRes] = await Promise.all([
        axios.get(`${API}/api/admin/overview`, { headers }),
        axios.get(`${API}/api/admin/users`, { headers }),
        axios.get(`${API}/api/admin/riders`, { headers }),
        axios.get(`${API}/api/admin/captains`, { headers }),
        axios.get(`${API}/api/admin/pending-captains`, { headers }),
        axios.get(`${API}/api/admin/rides`, { headers }),
      ]);

      setOverview(overviewRes.data || {});
      setUsers(usersRes.data || []);
      setRiders(ridersRes.data || []);
      setCaptains(captainsRes.data || []);
      setPendingCaptains(pendingRes.data || []);
      setRides(ridesRes.data || []);
    } catch (err) {
      console.error(err);
      setError(err.response?.data?.message || "Failed to fetch data");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchData(); }, []);

  const handleApprove = async (id) => {
    try {
      await axios.put(`${API}/api/admin/captain/${id}/approve`, {}, { headers: { Authorization: `Bearer ${token}` } });
      fetchData();
    } catch (err) {
      setError(err.response?.data?.message || "Failed to approve captain");
    }
  };

  const handleReject = async (id) => {
    try {
      await axios.put(`${API}/api/admin/captain/${id}/reject`, {}, { headers: { Authorization: `Bearer ${token}` } });
      fetchData();
    } catch (err) {
      setError(err.response?.data?.message || "Failed to reject captain");
    }
  };

  const handleLogout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("role");
    navigate("/admin-login");
  };

  const openModal = (user) => { setSelectedUser(user); setModalOpen(true); };
  const closeModal = () => { setSelectedUser(null); setModalOpen(false); };

  return (
    <Box p={4}>
      <Box display="flex" justifyContent="space-between" alignItems="center" mb={3}>
        <Typography variant="h4">Rider App - Admin Dashboard</Typography>
        <Button variant="contained" color="error" onClick={handleLogout}>Logout</Button>
      </Box>

      <Tabs value={tab} onChange={(e, val) => setTab(val)} sx={{ mb: 3 }}>
        <Tab label="Overview" value="overview" />
        <Tab label="Users" value="users" />
        <Tab label="Riders" value="riders" />
        <Tab label="Captains" value="captains" />
        <Tab label="Pending Captains" value="pending" />
        <Tab label="Rides" value="rides" />
      </Tabs>

      {loading && <Box display="flex" justifyContent="center" my={2}><CircularProgress /></Box>}
      {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}

      {/* === Overview === */}
      {tab === "overview" && (
        <Grid container spacing={3}>
          {Object.entries(overview).map(([key, value]) => (
            <Grid item xs={12} sm={6} md={3} key={key}>
              <Card sx={{ textAlign: "center", py: 3 }}>
                <Typography variant="h6">{key.replace(/Count$/, "").replace(/([A-Z])/g, " $1")}</Typography>
                <Typography variant="h4">{value}</Typography>
              </Card>
            </Grid>
          ))}
        </Grid>
      )}

      {/* === Users === */}
      {tab === "users" && (
        <TableContainer component={Paper}>
          <Table>
            <TableHead>
              <TableRow>
                <TableCell>Name</TableCell>
                <TableCell>Email</TableCell>
                <TableCell>Mobile</TableCell>
                <TableCell>Role</TableCell>
                <TableCell>Status</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {users.map(u => (
                <TableRow key={u._id} sx={{ cursor: "pointer" }} onClick={() => openModal(u)}>
                  <TableCell>{u.fullName}</TableCell>
                  <TableCell>{u.email}</TableCell>
                  <TableCell>{u.mobile}</TableCell>
                  <TableCell>{u.role}</TableCell>
                  <TableCell>{u.approvalStatus || "-"}</TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </TableContainer>
      )}

      {/* === Riders === */}
      {tab === "riders" && (
        <TableContainer component={Paper}>
          <Table>
            <TableHead>
              <TableRow>
                <TableCell>Name</TableCell>
                <TableCell>Email</TableCell>
                <TableCell>Mobile</TableCell>
                <TableCell>Status</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {riders.map(r => (
                <TableRow key={r._id} sx={{ cursor: "pointer" }} onClick={() => openModal(r)}>
                  <TableCell>{r.fullName}</TableCell>
                  <TableCell>{r.email}</TableCell>
                  <TableCell>{r.mobile}</TableCell>
                  <TableCell>{r.status}</TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </TableContainer>
      )}

      {/* === Captains === */}
      {tab === "captains" && (
        <TableContainer component={Paper}>
          <Table>
            <TableHead>
              <TableRow>
                <TableCell>Name</TableCell>
                <TableCell>Email</TableCell>
                <TableCell>Documents</TableCell>
                <TableCell>Status</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {captains.map(c => (
                <TableRow key={c._id} sx={{ cursor: "pointer" }} onClick={() => openModal(c)}>
                  <TableCell>{c.fullName}</TableCell>
                  <TableCell>{c.email}</TableCell>
                  <TableCell>{c.documents?.length || 0}</TableCell>
                  <TableCell>{c.status}</TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </TableContainer>
      )}

      {/* === Pending Captains === */}
      {tab === "pending" && (
        <TableContainer component={Paper}>
          <Table>
            <TableHead>
              <TableRow>
                <TableCell>Name</TableCell>
                <TableCell>Email</TableCell>
                <TableCell>Status</TableCell>
                <TableCell>Actions</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {pendingCaptains.map(p => (
                <TableRow key={p._id}>
                  <TableCell>{p.fullName}</TableCell>
                  <TableCell>{p.email}</TableCell>
                  <TableCell>{p.status}</TableCell>
                  <TableCell>
                    <Button size="small" variant="contained" color="success" sx={{ mr: 1 }} onClick={() => handleApprove(p._id)}>Approve</Button>
                    <Button size="small" variant="contained" color="error" onClick={() => handleReject(p._id)}>Reject</Button>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </TableContainer>
      )}

      {/* === Rides === */}
      {tab === "rides" && (
        <TableContainer component={Paper}>
          <Table>
            <TableHead>
              <TableRow>
                <TableCell>Rider</TableCell>
                <TableCell>Captain</TableCell>
                <TableCell>Pickup</TableCell>
                <TableCell>Drop</TableCell>
                <TableCell>Fare</TableCell>
                <TableCell>Status</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {rides.map(r => (
                <TableRow key={r._id}>
                  <TableCell>{r.rider?.fullName || "-"}</TableCell>
                  <TableCell>{r.captain?.fullName || "-"}</TableCell>
                  <TableCell>{r.pickup}</TableCell>
                  <TableCell>{r.drop}</TableCell>
                  <TableCell>{r.fare}</TableCell>
                  <TableCell>{r.status}</TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </TableContainer>
      )}

      {/* === Modal for User/Rider/Captain Details === */}
      <Modal open={modalOpen} onClose={closeModal}>
        <Box sx={{ position: "absolute", top: "50%", left: "50%", transform: "translate(-50%, -50%)", width: 450, bgcolor: "background.paper", borderRadius: 2, p: 3 }}>
          {selectedUser ? (
            <>
              <Typography variant="h5" sx={{ mb: 2 }}>{selectedUser.fullName}</Typography>
              <Typography>Email: {selectedUser.email}</Typography>
              {selectedUser.mobile && <Typography>Mobile: {selectedUser.mobile}</Typography>}
              <Typography>Status: {selectedUser.status || selectedUser.approvalStatus || "-"}</Typography>
              {selectedUser.documents && selectedUser.documents.length > 0 && (
                <>
                  <Typography sx={{ mt: 2 }}>Documents:</Typography>
                  {selectedUser.documents.map((doc, i) => (
                    <Box key={i}>
                      <a href={doc.url} target="_blank" rel="noreferrer">{doc.name}</a>
                    </Box>
                  ))}
                </>
              )}
              <Button fullWidth sx={{ mt: 3 }} variant="contained" onClick={closeModal}>Close</Button>
            </>
          ) : <CircularProgress />}
        </Box>
      </Modal>
    </Box>
  );
}
